module counter_4bit_sync_reset(
    input clk,
    input rst,
    output reg [3:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst)
            q <= 4'b0;
        else
            q <= q + 1;
    end

endmodule
